[
    {
        "role": "paragraph",
        "segment": "The purpose of McCall's quality model is to provide a framework for understanding and measuring software quality by relating external quality factors to product quality criteria.",
        "citations": [
            {
                "type": "source_text",
                "content": "Figure 1.5 is an example of an early quality model built by McCall and his colleagues to show how external quality factors (on the left-hand side) relate to product quality criteria (on the right-hand side). McCall associated each right-hand criterion with a measurement to indicate the degree to which an element of quality was addressed (McCall, Richards, and Walters 1977).",
                "img_id": null
            }
        ]
    },
    {
        "role": "sentence",
        "segment": "It helps to connect the user's external view of software quality with the developer's internal view.",
        "citations": [
            {
                "type": "source_text",
                "content": "For this reason, we often build models to relate the user's external view to the developer's internal view of the software.",
                "img_id": null
            }
        ]
    },
    {
        "role": "sentence",
        "segment": "The model identifies characteristics that contribute to overall quality and provides measurements to compare one product with another.",
        "citations": [
            {
                "type": "source_text",
                "content": "We try to measure software quality so that we can compare one product with another. To do so, we identify those aspects of the system that contribute to its overall quality.",
                "img_id": null
            }
        ]
    }
]

