[
    {
        "role": "paragraph",
        "segment": "An activity is a part of the project that takes place over a period of time, having a beginning and an end, whereas a milestone is the completion of an activity—a particular point in time.",
        "citations": [
            {
                "type": "source_text",
                "content": "An activity is a part of the project that takes place over a period of time, whereas a milestone is the completion of an activity-a particular point in time. Thus, an activity has a beginning and an end, whereas a milestone is the end of a specially designated activity.",
                "img_id": null
            }
        ]
    },
    {
        "role": "paragraph",
        "segment": "For example, the development of an online operator tutorial and its associated programs is an activity; it culminates in the demonstration of those functions to the customer, which is the milestone.",
        "citations": [
            {
                "type": "source_text",
                "content": "For example, the customer may want the system to be accompanied by an online operator tutorial. The development of the tutorial and its associated programs is an activity; it culminates in the demonstration of those functions to the customer: the milestone.",
                "img_id": null
            }
        ]
    }
]

