            }
        ],
        "type": null
    },
    {
        "role": "paragraph",
        "segment": "For example, Kai, a rational extrovert, judges her colleagues by the results they produce and prioritizes efficiency in decision making.",
        "citations": [
            {
                "type": "source_text",
                "content": "Kai, a rational extrovert, judges her colleagues by the results they produce. When making a decision, her top priority is efficiency.",
