            }
        ],
        "type": null
    },
    {
        "role": "sentence",
        "segment": "She wants to know only the bottom line and does not need to see documents or hear explanations supporting each option.",
        "citations": [
            {
                "type": "source_text",
                "content": "She wants to know only the bottom line. She examines her options and their probable effects, but she does not need to see documents or hear explanations supporting each option.",
                "img_id": null
            }
        ],
        "type": null
    },
    {
        "role": "sentence",
        "segment": "If her time is wasted or her efficiency is hampered, she asserts her authority to regain control of the situation, making sound decisions quickly.",
        "citations": [
            {
                "type": "source_text",
                "content": "If her time is wasted or her efficiency is hampered in some way, she asserts her authority to regain control of the situation.Thus, Kai is good at making sound decisions quickly.",
